static int mpj_valid_type_id(int type_id) {
    return type_id >= 0 && (size_t)type_id < mpj_type_count();
}

static mpj_buffer *mpj_buffer_from_sbuffer(const msgpack_sbuffer *sbuf) {
    mpj_buffer *buffer = (mpj_buffer *)calloc(1, sizeof(*buffer));
    if (!buffer) return NULL;
    if (sbuf->size == 0) return buffer;
    buffer->data = (uint8_t *)malloc(sbuf->size);
    if (!buffer->data) { free(buffer); return NULL; }
    memcpy(buffer->data, sbuf->data, sbuf->size);
    buffer->size = sbuf->size;
    return buffer;
}

const uint8_t *mpj_buffer_data(const mpj_buffer *buffer) {
    return buffer ? buffer->data : NULL;
}

size_t mpj_buffer_size(const mpj_buffer *buffer) {
    return buffer ? buffer->size : 0;
}

void mpj_buffer_delete(mpj_buffer *buffer) {
    if (!buffer) return;
    free(buffer->data);
    free(buffer);
}

struct mpj_value {
    int kind;
    union {
        int boolean;
        int64_t i64;
        uint64_t u64;
        double f64;
        struct { uint8_t *data; size_t size; } bytes;
        struct { mpj_value **items; size_t size; } array;
        struct { mpj_value **keys; mpj_value **values; size_t size; } map;
    } as;
};

static mpj_value *mpj_value_alloc(int kind) {
    mpj_value *value = (mpj_value *)calloc(1, sizeof(*value));
    if (value) value->kind = kind;
    return value;
}

mpj_value *mpj_value_new_nil(void) { return mpj_value_alloc(MPJ_VALUE_NIL); }

mpj_value *mpj_value_new_bool(int value) {
    mpj_value *out = mpj_value_alloc(MPJ_VALUE_BOOL);
    if (out) out->as.boolean = value ? 1 : 0;
    return out;
}

mpj_value *mpj_value_new_int(int64_t value) {
    mpj_value *out = mpj_value_alloc(MPJ_VALUE_INT);
    if (out) out->as.i64 = value;
    return out;
}

mpj_value *mpj_value_new_uint(uint64_t value) {
    mpj_value *out = mpj_value_alloc(MPJ_VALUE_UINT);
    if (out) out->as.u64 = value;
    return out;
}

mpj_value *mpj_value_new_float(double value) {
    mpj_value *out = mpj_value_alloc(MPJ_VALUE_FLOAT);
    if (out) out->as.f64 = value;
    return out;
}

mpj_value *mpj_value_new_number(double value) {
    if (value >= 0.0 && value <= 9007199254740991.0) {
        uint64_t n = (uint64_t)value;
        if ((double)n == value) return mpj_value_new_uint(n);
    }
    if (value >= -9007199254740991.0 && value <= 9007199254740991.0) {
        int64_t n = (int64_t)value;
        if ((double)n == value) return mpj_value_new_int(n);
    }
    return mpj_value_new_float(value);
}

static mpj_value *mpj_value_new_bytes(int kind, const uint8_t *data, size_t size) {
    mpj_value *out = mpj_value_alloc(kind);
    if (!out) return NULL;
    out->as.bytes.size = size;
    if (size == 0) return out;
    out->as.bytes.data = (uint8_t *)malloc(size);
    if (!out->as.bytes.data) { free(out); return NULL; }
    memcpy(out->as.bytes.data, data, size);
    return out;
}

mpj_value *mpj_value_new_string(const uint8_t *data, size_t size) { return mpj_value_new_bytes(MPJ_VALUE_STRING, data, size); }
mpj_value *mpj_value_new_binary(const uint8_t *data, size_t size) { return mpj_value_new_bytes(MPJ_VALUE_BINARY, data, size); }

mpj_value *mpj_value_new_array(size_t size) {
    mpj_value *out = mpj_value_alloc(MPJ_VALUE_ARRAY);
    if (!out) return NULL;
    out->as.array.size = size;
    if (size == 0) return out;
    out->as.array.items = (mpj_value **)calloc(size, sizeof(mpj_value *));
    if (!out->as.array.items) { free(out); return NULL; }
    return out;
}

mpj_value *mpj_value_new_map(size_t size) {
    mpj_value *out = mpj_value_alloc(MPJ_VALUE_MAP);
    if (!out) return NULL;
    out->as.map.size = size;
    if (size == 0) return out;
    out->as.map.keys = (mpj_value **)calloc(size, sizeof(mpj_value *));
    out->as.map.values = (mpj_value **)calloc(size, sizeof(mpj_value *));
    if (!out->as.map.keys || !out->as.map.values) { free(out->as.map.keys); free(out->as.map.values); free(out); return NULL; }
    return out;
}

void mpj_value_free(mpj_value *value) {
    if (!value) return;
    if (value->kind == MPJ_VALUE_STRING || value->kind == MPJ_VALUE_BINARY) {
        free(value->as.bytes.data);
    } else if (value->kind == MPJ_VALUE_ARRAY) {
        for (size_t i = 0; i < value->as.array.size; ++i) mpj_value_free(value->as.array.items[i]);
        free(value->as.array.items);
    } else if (value->kind == MPJ_VALUE_MAP) {
        for (size_t i = 0; i < value->as.map.size; ++i) { mpj_value_free(value->as.map.keys[i]); mpj_value_free(value->as.map.values[i]); }
        free(value->as.map.keys);
        free(value->as.map.values);
    }
    free(value);
}

int mpj_value_array_set(mpj_value *array, size_t index, mpj_value *item) {
    if (!array || array->kind != MPJ_VALUE_ARRAY || index >= array->as.array.size) return -1;
    mpj_value_free(array->as.array.items[index]);
    array->as.array.items[index] = item;
    return 0;
}

int mpj_value_map_set(mpj_value *map, size_t index, mpj_value *key, mpj_value *value) {
    if (!map || map->kind != MPJ_VALUE_MAP || index >= map->as.map.size) return -1;
    mpj_value_free(map->as.map.keys[index]);
    mpj_value_free(map->as.map.values[index]);
    map->as.map.keys[index] = key;
    map->as.map.values[index] = value;
    return 0;
}

static int mpj_pack_value(msgpack_packer *pk, const mpj_value *value) {
    if (!pk) return -1;
    if (!value) return msgpack_pack_nil(pk);
    switch (value->kind) {
    case MPJ_VALUE_NIL: return msgpack_pack_nil(pk);
    case MPJ_VALUE_BOOL: return value->as.boolean ? msgpack_pack_true(pk) : msgpack_pack_false(pk);
    case MPJ_VALUE_INT: return msgpack_pack_int64(pk, value->as.i64);
    case MPJ_VALUE_UINT: return msgpack_pack_uint64(pk, value->as.u64);
    case MPJ_VALUE_FLOAT: return msgpack_pack_double(pk, value->as.f64);
    case MPJ_VALUE_STRING:
        if (msgpack_pack_str(pk, value->as.bytes.size) != 0) return -1;
        return msgpack_pack_str_body(pk, (const char *)value->as.bytes.data, value->as.bytes.size);
    case MPJ_VALUE_BINARY:
        if (msgpack_pack_bin(pk, value->as.bytes.size) != 0) return -1;
        return msgpack_pack_bin_body(pk, value->as.bytes.data, value->as.bytes.size);
    case MPJ_VALUE_ARRAY:
        if (msgpack_pack_array(pk, value->as.array.size) != 0) return -1;
        for (size_t i = 0; i < value->as.array.size; ++i) if (mpj_pack_value(pk, value->as.array.items[i]) != 0) return -1;
        return 0;
    case MPJ_VALUE_MAP:
        if (msgpack_pack_map(pk, value->as.map.size) != 0) return -1;
        for (size_t i = 0; i < value->as.map.size; ++i) {
            if (mpj_pack_value(pk, value->as.map.keys[i]) != 0) return -1;
            if (mpj_pack_value(pk, value->as.map.values[i]) != 0) return -1;
        }
        return 0;
    default: return -1;
    }
}

mpj_buffer *mpj_value_pack_bytes(const mpj_value *value) {
    if (!value) return NULL;
    msgpack_sbuffer sbuf;
    msgpack_packer pk;
    msgpack_sbuffer_init(&sbuf);
    msgpack_packer_init(&pk, &sbuf, msgpack_sbuffer_write);
    if (mpj_pack_value(&pk, value) != 0) { msgpack_sbuffer_destroy(&sbuf); return NULL; }
    mpj_buffer *buffer = mpj_buffer_from_sbuffer(&sbuf);
    msgpack_sbuffer_destroy(&sbuf);
    return buffer;
}

static mpj_value *mpj_value_from_object(const msgpack_object *obj) {
    if (!obj) return NULL;
    switch (obj->type) {
    case MSGPACK_OBJECT_NIL: return mpj_value_new_nil();
    case MSGPACK_OBJECT_BOOLEAN: return mpj_value_new_bool(obj->via.boolean);
    case MSGPACK_OBJECT_POSITIVE_INTEGER: return mpj_value_new_uint(obj->via.u64);
    case MSGPACK_OBJECT_NEGATIVE_INTEGER: return mpj_value_new_int(obj->via.i64);
    case MSGPACK_OBJECT_FLOAT32:
    case MSGPACK_OBJECT_FLOAT64: return mpj_value_new_float(obj->via.f64);
    case MSGPACK_OBJECT_STR: return mpj_value_new_string((const uint8_t *)obj->via.str.ptr, obj->via.str.size);
    case MSGPACK_OBJECT_BIN: return mpj_value_new_binary((const uint8_t *)obj->via.bin.ptr, obj->via.bin.size);
    case MSGPACK_OBJECT_ARRAY: {
        mpj_value *out = mpj_value_new_array(obj->via.array.size);
        if (!out) return NULL;
        for (uint32_t i = 0; i < obj->via.array.size; ++i) mpj_value_array_set(out, i, mpj_value_from_object(&obj->via.array.ptr[i]));
        return out;
    }
    case MSGPACK_OBJECT_MAP: {
        mpj_value *out = mpj_value_new_map(obj->via.map.size);
        if (!out) return NULL;
        for (uint32_t i = 0; i < obj->via.map.size; ++i) mpj_value_map_set(out, i, mpj_value_from_object(&obj->via.map.ptr[i].key), mpj_value_from_object(&obj->via.map.ptr[i].val));
        return out;
    }
    default: return NULL;
    }
}

mpj_value *mpj_value_unpack_bytes(const uint8_t *data, size_t size) {
    if (!data && size > 0) return NULL;
    msgpack_unpacked result;
    msgpack_unpacked_init(&result);
    size_t off = 0;
    msgpack_unpack_return ret = msgpack_unpack_next(&result, (const char *)data, size, &off);
    if (ret != MSGPACK_UNPACK_SUCCESS) { msgpack_unpacked_destroy(&result); return NULL; }
    mpj_value *out = mpj_value_from_object(&result.data);
    msgpack_unpacked_destroy(&result);
    return out;
}

int mpj_value_kind(const mpj_value *value) { return value ? value->kind : -1; }
int mpj_value_bool(const mpj_value *value) { return value && value->kind == MPJ_VALUE_BOOL ? value->as.boolean : 0; }
int64_t mpj_value_int(const mpj_value *value) { return value && value->kind == MPJ_VALUE_INT ? value->as.i64 : 0; }
uint64_t mpj_value_uint(const mpj_value *value) { return value && value->kind == MPJ_VALUE_UINT ? value->as.u64 : 0; }
double mpj_value_float(const mpj_value *value) { return value && value->kind == MPJ_VALUE_FLOAT ? value->as.f64 : 0.0; }
double mpj_value_number(const mpj_value *value) {
    if (!value) return 0.0;
    if (value->kind == MPJ_VALUE_INT) return (double)value->as.i64;
    if (value->kind == MPJ_VALUE_UINT) return (double)value->as.u64;
    if (value->kind == MPJ_VALUE_FLOAT) return value->as.f64;
    return 0.0;
}
const uint8_t *mpj_value_data(const mpj_value *value) {
    if (!value || (value->kind != MPJ_VALUE_STRING && value->kind != MPJ_VALUE_BINARY)) return NULL;
    return value->as.bytes.data;
}
size_t mpj_value_size(const mpj_value *value) {
    if (!value) return 0;
    if (value->kind == MPJ_VALUE_STRING || value->kind == MPJ_VALUE_BINARY) return value->as.bytes.size;
    if (value->kind == MPJ_VALUE_ARRAY) return value->as.array.size;
    if (value->kind == MPJ_VALUE_MAP) return value->as.map.size;
    return 0;
}
const mpj_value *mpj_value_array_get(const mpj_value *array, size_t index) {
    if (!array || array->kind != MPJ_VALUE_ARRAY || index >= array->as.array.size) return NULL;
    return array->as.array.items[index];
}
const mpj_value *mpj_value_map_key(const mpj_value *map, size_t index) {
    if (!map || map->kind != MPJ_VALUE_MAP || index >= map->as.map.size) return NULL;
    return map->as.map.keys[index];
}
const mpj_value *mpj_value_map_value(const mpj_value *map, size_t index) {
    if (!map || map->kind != MPJ_VALUE_MAP || index >= map->as.map.size) return NULL;
    return map->as.map.values[index];
}

size_t mpj_type_count(void) {
    return sizeof(mpj_types) / sizeof(mpj_types[0]);
}

const char *mpj_type_name(size_t type_id) {
    if (type_id >= mpj_type_count()) return NULL;
    return mpj_types[type_id].name;
}

int mpj_type_id(const char *type_name) {
    if (!type_name) return -1;
    for (size_t i = 0; i < mpj_type_count(); ++i) {
        if (strcmp(type_name, mpj_types[i].name) == 0) return (int)i;
    }
    return -1;
}

static const mpj_field_entry *mpj_field_at(int type_id, size_t field_id) {
    if (!mpj_valid_type_id(type_id)) return NULL;
    if (field_id >= mpj_types[type_id].field_count) return NULL;
    return &mpj_types[type_id].fields[field_id];
}

size_t mpj_field_count(int type_id) {
    if (!mpj_valid_type_id(type_id)) return 0;
    return mpj_types[type_id].field_count;
}

const char *mpj_field_name(int type_id, size_t field_id) {
    const mpj_field_entry *field = mpj_field_at(type_id, field_id);
    return field ? field->name : NULL;
}

const char *mpj_field_c_type(int type_id, size_t field_id) {
    const mpj_field_entry *field = mpj_field_at(type_id, field_id);
    return field ? field->c_type : NULL;
}

int mpj_field_key_kind(int type_id, size_t field_id) {
    const mpj_field_entry *field = mpj_field_at(type_id, field_id);
    return field ? field->key_kind : -1;
}

const char *mpj_field_key_string(int type_id, size_t field_id) {
    const mpj_field_entry *field = mpj_field_at(type_id, field_id);
    return field ? field->key_string : NULL;
}

int64_t mpj_field_key_int(int type_id, size_t field_id) {
    const mpj_field_entry *field = mpj_field_at(type_id, field_id);
    return field ? field->key_int : 0;
}

void *mpj_new(int type_id) {
    if (!mpj_valid_type_id(type_id)) return NULL;
    return calloc(1, mpj_types[type_id].size);
}

int mpj_delete(int type_id, void *value) {
    if (!mpj_valid_type_id(type_id)) return -1;
    if (!value) return 0;
    mpj_types[type_id].free_fn(value);
    free(value);
    return 0;
}

mpj_buffer *mpj_pack_bytes(int type_id, const void *value) {
    if (!mpj_valid_type_id(type_id) || !value) return NULL;
    msgpack_sbuffer sbuf;
    msgpack_packer pk;
    msgpack_sbuffer_init(&sbuf);
    msgpack_packer_init(&pk, &sbuf, msgpack_sbuffer_write);
    if (mpj_types[type_id].pack_fn(&pk, value) != 0) { msgpack_sbuffer_destroy(&sbuf); return NULL; }
    mpj_buffer *buffer = mpj_buffer_from_sbuffer(&sbuf);
    msgpack_sbuffer_destroy(&sbuf);
    return buffer;
}

int mpj_unpack_bytes(int type_id, const uint8_t *data, size_t size, void *out) {
    if (!mpj_valid_type_id(type_id) || !data || !out) return -1;
    msgpack_unpacked result;
    msgpack_unpacked_init(&result);
    size_t off = 0;
    msgpack_unpack_return ret = msgpack_unpack_next(&result, (const char *)data, size, &off);
    if (ret != MSGPACK_UNPACK_SUCCESS) { msgpack_unpacked_destroy(&result); return -1; }
    int rc = mpj_types[type_id].unpack_fn(&result.data, out);
    msgpack_unpacked_destroy(&result);
    return rc;
}
